public static string Reverse(string s)
{
    char[] c = s.ToCharArray();
    int left = 0, right = c.Length - 1;
    while (left < right)
    {
        (c[left], c[right]) = (c[right], c[left]); // tuple swap
        left++;
        right--;
    }
    return new string(c);
}

