public static IList<int> MajorityElement(int[] nums)
{
    int cand1 = 0, cand2 = 1, c1 = 0, c2 = 0; // cand2 != cand1 initially
    foreach (int x in nums)
    {
        if (x == cand1) c1++;
        else if (x == cand2) c2++;
        else if (c1 == 0) { cand1 = x; c1 = 1; }
        else if (c2 == 0) { cand2 = x; c2 = 1; }
        else { c1--; c2--; }
    }

    c1 = 0; c2 = 0;
    foreach (int x in nums)
    {
        if (x == cand1) c1++;
        else if (x == cand2) c2++;
    }

    var res = new List<int>();
    if (c1 > nums.Length / 3) res.Add(cand1);
    if (c2 > nums.Length / 3) res.Add(cand2);
    return res;
}

