public static Dictionary<int, int> CountOccurrences(int[] nums)
{
    var counts = new Dictionary<int, int>();
    foreach (int x in nums)
    {
        counts.TryGetValue(x, out int c);
        counts[x] = c + 1;
    }
    return counts;
}

