public static IList<int> FindDuplicates(int[] nums)
{
    var seen = new HashSet<int>();
    var dups = new HashSet<int>();
    foreach (int x in nums)
        if (!seen.Add(x)) dups.Add(x);
    return dups.ToList();
}

