public static List<int> Primes(int n)
{
    var isComposite = new bool[n + 1];
    var primes = new List<int>();
    for (int p = 2; p <= n; p++)
    {
        if (isComposite[p]) continue;
        primes.Add(p);
        for (long m = (long)p * p; m <= n; m += p)
            isComposite[m] = true;
    }
    return primes;
}

